interface Calc {
    int oddSum();
    int evenSum();
}

class CalcImpl implements Calc {
    int[] arr;
    CalcImpl(int[] arr) { this.arr = arr; }
    public int oddSum() {
        int sum = 0;
        for (int v : arr) if (v % 2 != 0) sum += v;
        return sum;
    }
    public int evenSum() {
        int sum = 0;
        for (int v : arr) if (v % 2 == 0) sum += v;
        return sum;
    }
}

public class Main {
    public static void main(String[] args) {
        int[] arr = {1, 2, 3, 4, 5, 6, 7, 8, 9};
        Calc c = new CalcImpl(arr);
        System.out.print(c.oddSum() + ", " + c.evenSum());
    }
}

