public class Main {
    static String str = "aabbccdd";
    static String result = "";

    public static void removeDup(int idx) {
        if (idx < 0) return;
        char ch = str.charAt(idx);
        if (result.indexOf(ch) == -1) {
            result += ch;
        }
        removeDup(idx - 1);
    }

    public static void main(String[] args) {
        removeDup(str.length() - 1);
        System.out.print(result);
    }
}

#include <stdio.h>
void swap() {
    int a = 11, b = 19, temp;
    temp = a; a = b; b = temp;
}
int main() {
    int a = 11, b = 19;
    swap();
    switch(a) {
        case 1: b += 1; break;
        case 11: b += 2;
        default: b += 3; break;
    }
    printf("%d", a - b);
    return 0;
}

